  app.get("/api/stripe/products", async (_req: Request, res: Response) => {
    try {
      const { db } = await import("./db");
      const { sql } = await import("drizzle-orm");
      const result = await db.execute(
        sql`SELECT
              p.id as product_id,
              p.name as product_name,
              p.description as product_description,
              p.active as product_active,
              p.metadata as product_metadata,
              pr.id as price_id,
              pr.unit_amount,
              pr.currency,
              pr.recurring,
              pr.active as price_active,
              pr.metadata as price_metadata
            FROM stripe.products p
            LEFT JOIN stripe.prices pr ON pr.product = p.id AND pr.active = true
            WHERE p.active = true
            ORDER BY p.name, pr.unit_amount`
      );

      interface ProductPriceRow {
        product_id: string;
        product_name: string;
        product_description: string | null;
        product_active: boolean;
        product_metadata: Record<string, string> | null;
        price_id: string | null;
        unit_amount: number | null;
        currency: string | null;
        recurring: { interval: string } | null;
        price_active: boolean | null;
        price_metadata: Record<string, string> | null;
      }

      interface ProductData {
        id: string;
        name: string;
        description: string | null;
        active: boolean;
        metadata: Record<string, string> | null;
        prices: Array<{
          id: string;
          unitAmount: number | null;
          currency: string | null;
          recurring: { interval: string } | null;
          active: boolean | null;
          metadata: Record<string, string> | null;
        }>;
      }

      const productsMap = new Map<string, ProductData>();
      for (const row of result.rows as unknown as ProductPriceRow[]) {
        if (!productsMap.has(row.product_id)) {
          productsMap.set(row.product_id, {
            id: row.product_id,
            name: row.product_name,
            description: row.product_description,
            active: row.product_active,
            metadata: row.product_metadata,
            prices: [],
          });
        }
        if (row.price_id) {
          productsMap.get(row.product_id)!.prices.push({
            id: row.price_id,
            unitAmount: row.unit_amount,
            currency: row.currency,
            recurring: row.recurring,
            active: row.price_active,
            metadata: row.price_metadata,
          });
        }
      }
      return res.json({ data: Array.from(productsMap.values()) });
    } catch (err) {
      return res.json({ data: [] });
    }
  });

