  function formatPerplexityCitations(response: any): string {
    if (!response?.citations || !Array.isArray(response.citations) || response.citations.length === 0) return "";
    return "\n\n---\n**Sources:**\n" + response.citations.map((url: string, i: number) => `${i + 1}. ${url}`).join("\n");
  }

  function formatOpenRouterError(error: any): string {
    if (!error) return "OpenRouter request failed";
    const status = error.status || error.statusCode;
    const msg = error.message || "";
    if (status === 402 || msg.includes("insufficient")) return "OpenRouter: Insufficient credits or model requires payment";
    if (status === 429 || msg.includes("rate")) return "OpenRouter: Rate limit exceeded — please wait and try again";
    if (status === 404 || msg.includes("not found") || msg.includes("No available")) return "OpenRouter: Model is unavailable — it may be offline, incompatible with privacy settings, or require a paid endpoint";
    if (status === 403 || msg.includes("privacy") || msg.includes("data_collection")) return "OpenRouter: Model unavailable due to privacy policy conflict — this model does not support privacy-safe requests";
    if (status === 503 || msg.includes("overloaded")) return "OpenRouter: Model is temporarily overloaded — try a different model or retry later";
    return `OpenRouter error: ${msg.substring(0, 200)}`;
  }

  const BYOK_SECRET_KEYS: Record<string, string> = {
    openai: "OPENAI_API_KEY",
    anthropic: "ANTHROPIC_API_KEY",
    google: "GOOGLE_API_KEY",
    openrouter: "OPENROUTER_API_KEY",
    perplexity: "PERPLEXITY_API_KEY",
    mistral: "MISTRAL_API_KEY",
  };

  async function resolveProviderClients(projectId: string | undefined, provider: string, userId?: string): Promise<{ anthropicClient: Anthropic; openaiClient: OpenAI; geminiClient: GoogleGenAI; credMode: string; byokNoKey?: boolean }> {
    if (projectId && userId) {
      const project = await storage.getProject(projectId);
      if (!project || project.userId !== userId) {
        return { anthropicClient: anthropic, openaiClient: openai, geminiClient: gemini, credMode: "managed" };
      }
    }
    if (projectId) {
      const cfg = await storage.getAiCredentialConfig(projectId, provider);
      if (cfg?.mode === "byok") {
        let apiKey: string | null = null;
        if (cfg.apiKey) {
          apiKey = decrypt(cfg.apiKey);
        } else {
          const secretKey = BYOK_SECRET_KEYS[provider];
          if (secretKey) {
            const envVars = await storage.getProjectEnvVars(projectId);
            const ev = envVars.find(e => e.key === secretKey);
            if (ev?.encryptedValue) {
              apiKey = decrypt(ev.encryptedValue);
            }
          }
        }
        if (apiKey) {
          if (provider === "anthropic") {
            return { anthropicClient: new Anthropic({ apiKey }), openaiClient: openai, geminiClient: gemini, credMode: "byok" };
          }
          if (provider === "openai" || provider === "openrouter") {
            const baseURL = provider === "openrouter" ? "https://openrouter.ai/api/v1" : undefined;
            return { anthropicClient: anthropic, openaiClient: new OpenAI({ apiKey, ...(baseURL ? { baseURL } : {}) }), geminiClient: gemini, credMode: "byok" };
          }
          if (provider === "google") {
            return { anthropicClient: anthropic, openaiClient: openai, geminiClient: new GoogleGenAI({ apiKey }), credMode: "byok" };
          }
          if (provider === "perplexity") {
            return { anthropicClient: anthropic, openaiClient: new OpenAI({ apiKey, baseURL: "https://api.perplexity.ai" }), geminiClient: gemini, credMode: "byok" };
          }
          if (provider === "mistral") {
            return { anthropicClient: anthropic, openaiClient: new OpenAI({ apiKey, baseURL: "https://api.mistral.ai/v1" }), geminiClient: gemini, credMode: "byok" };
          }
        }
        return { anthropicClient: anthropic, openaiClient: openai, geminiClient: gemini, credMode: "byok", byokNoKey: true };
      }
    }
    return { anthropicClient: anthropic, openaiClient: openai, geminiClient: gemini, credMode: "managed" };
  }

